mapper.insert:
	/* wms-master-store-sql-oracle.xml - insertTWorkMstStore */
	INSERT INTO TWORK_MST_STORE
	(
		  OWKEY	
		, CTKEY
	    , STORE_KEY
	    , DCKEY
	    , STORE_NAME
		, FCTYPE
		, DELYN
		, DLDAY
		, ZIPCODE
	    , TEL1
	    , ADDRESS1
	    , ADDRESS2
	    , SV_NM
	    , OWNER_NAME
	    , REGNO
	    , TEL2
	    , ADDRID
		, ISMANAGESTORE
		, CLOSDATE
		, INSERTDATE
		, INSERTURKEY
		, UPDATEDATE
		, UPDATEURKEY
		, CUST_TYPE
		, CUST_TYPE_DETAIL
	) VALUES (
		  #{owkey}
		, #{ctkey}
	    , #{storeKey}
	    , #{rndkey}
	    , #{storeName}
		, '0'
		, 'N'
		, 'N'
		, #{zipcode}
        , #{tel1}
        , #{address1}
        , #{address2}
        , #{scNm}
        , #{ownerName}
        , #{regno}
        , #{tel2}
        , #{addrid}
        , 'N'
        , SUBSTR(#{closdate}, 0, 14)
		, #{sysdate}
		, #{surkey}
		, #{sysdate}
		, #{surkey}
		, #{custType}
		, #{custTypeDetail}
	)

mapper.update:
/* wms-master-store-sql-oracle.xml - updateTWorkMstStore */
UPDATE TWORK_MST_STORE
	SET ZIPCODE					= #{zipcode}
	  ,ADDRESS1					= #{address1}
	  ,ADDRESS2					= #{address2}

	  ,STORE_NAME				= #{storeName}
	  ,TEL1						= #{tel1}
	  ,SV_NM					= #{scNm}
	  ,OWNER_NAME				= #{owner_name}
	  ,REGNO					= #{regno}
	  ,CLOSEDATE				= #{closedate}
	  ,TEL2						= #{tel2}
	  ,ADDRID					= #{addrid}
	  ,CLOSDATE				= SUBSTR(#{closdate}, 0, 14)
	  ,HLMANAGETYPE				= #{hlmanagetype}
	  ,CUST_TYPE				= #{custType}
	  ,CUST_TYPE_DETAIL	    	= #{custTypeDetail}
	  ,DELYN					= #{delyn}

	,UPDATEDATE				= #{sysdate}
	,UPDATEURKEY			= #{surkey}
WHERE
 	STORE_KEY = #{storeKey}

